// Hash the full MSBTE homepage to detect any change.
// Simpler than parsing notice structure which varies by site version.
const html = $input.first().json.data || '';
const staticData = $getWorkflowStaticData('global');

let hash = 0;
const str = String(html);
for (let i = 0; i < str.length; i++) {
  hash = (Math.imul(31, hash) + str.charCodeAt(i)) | 0;
}
const currentHash = String(hash);
const lastHash = staticData.lastPageHash || '';

if (currentHash === lastHash && lastHash !== '') {
  return [];
}

staticData.lastPageHash = currentHash;

return [{
  json: {
    changed: true,
    newNotices: [],
    allNotices: [],
    newNoticeCount: 0,
    totalFound: 0
  }
}];

const item = $input.first().json;
const notices = item.newNotices && item.newNotices.length > 0 ? item.newNotices : (item.allNotices || []).slice(0, 5);
const header = item.newNotices && item.newNotices.length > 0
  ? '📢 <b>' + item.newNotices.length + ' new MSBTE notice(s)</b>'
  : '📋 <b>MSBTE page changed</b> (' + (item.totalFound || 0) + ' notices found)';

const noticeLines = notices.map((n) => {
  const href = n.href.startsWith('http') ? n.href : 'https://msbte.ac.in' + n.href;
  return '• <a href=\'' + href + '\'>' + n.text.slice(0, 80) + '</a>';
}).join('\\n');

const text = [header, '', noticeLines, '', "🔗 <a href='https://msbte.ac.in/'>View all notices</a>"].join('\\n');

return [{ json: { text } }];
